CustomField.formula:
IF( MONTH(leaseworks__Delivery_Date__c)=1  ||  MONTH(leaseworks__Delivery_Date__c)=2 || MONTH(leaseworks__Delivery_Date__c)=3,'Q1 - ',
 IF(MONTH(leaseworks__Delivery_Date__c)=4  ||  MONTH(leaseworks__Delivery_Date__c)=5 || MONTH(leaseworks__Delivery_Date__c)=6, 'Q2 - ', 
  IF(MONTH(leaseworks__Delivery_Date__c)=7  ||  MONTH(leaseworks__Delivery_Date__c)=8 || MONTH(leaseworks__Delivery_Date__c)=9, 'Q3 - ' , 
    IF(MONTH(leaseworks__Delivery_Date__c)=10  ||  MONTH(leaseworks__Delivery_Date__c)=11 || MONTH(leaseworks__Delivery_Date__c)=12, 'Q4 - ', '') 
  ) 
 ) 
)+  TEXT(YEAR(leaseworks__Delivery_Date__c))
